// Custom cursor
const cDot = document.getElementById("cDot"),
  cRing = document.getElementById("cRing");
if (cDot && cRing) {
  document.body.classList.add("has-custom-cursor");
  let curX = 0, curY = 0, ringX = 0, ringY = 0;
  const moveCursor = (e) => {
    curX = e.clientX;
    curY = e.clientY;
    cDot.style.left = `${curX}px`;
    cDot.style.top = `${curY}px`;
  };
  window.addEventListener("mousemove", moveCursor);
  requestAnimationFrame(function ringLoop() {
    ringX += (curX - ringX) * 0.15;
    ringY += (curY - ringY) * 0.15;
    cRing.style.left = `${ringX}px`;
    cRing.style.top = `${ringY}px`;
    requestAnimationFrame(ringLoop);
  });
  const hoverTargets = document.querySelectorAll(
    "a, button, .nav-link, .event-cassette, .hero-btn-primary, .hero-btn-secondary, .featured-cta-btn, .filter-btn, .bento-feature-card"
  );
  hoverTargets.forEach((el) => {
    el.addEventListener("mouseenter", () => {
      cDot.classList.add("h");
      cRing.classList.add("h");
    });
    el.addEventListener("mouseleave", () => {
      cDot.classList.remove("h");
      cRing.classList.remove("h");
    });
  });
}

// Particle background init helper for index page
document.addEventListener("DOMContentLoaded", () => {
  if (typeof window.initParticleBackground === "function" && document.getElementById("canvas-particles")) {
    window.initParticleBackground("canvas-particles", "rgba(0, 120, 212, alpha)");
  }
});

// Restore overflow on page show (back navigation)
window.addEventListener("pageshow", () => {
  document.body.style.overflow = "";
});

// Hamburger nav
const hamburger = document.querySelector(".hamburger"),
  navMenu = document.querySelector(".nav-menu");
if (hamburger && navMenu) {
  hamburger.dataset.navInitialized = "true";
  const closeNavMenu = () => {
    hamburger.classList.remove("active");
    navMenu.classList.remove("active");
    document.body.style.overflow = "";
  };
  hamburger.addEventListener("click", (e) => {
    e.stopPropagation();
    hamburger.classList.toggle("active");
    navMenu.classList.toggle("active");
    document.body.style.overflow = navMenu.classList.contains("active") ? "hidden" : "";
  });
  document.addEventListener("click", (e) => {
    if (!hamburger.contains(e.target) && !navMenu.contains(e.target)) closeNavMenu();
  });
  navMenu.querySelectorAll("a").forEach((a) => a.addEventListener("click", closeNavMenu));
}

// Smooth scroll for anchor links
document.querySelectorAll('a[href^="#"]').forEach((link) => {
  link.addEventListener("click", function (e) {
    e.preventDefault();
    const target = document.querySelector(this.getAttribute("href"));
    const nav = document.querySelector(".nav-menu");
    const hb = document.querySelector(".hamburger");
    if (nav && nav.classList.contains("active")) {
      nav.classList.remove("active");
      hb.classList.remove("active");
      document.body.style.overflow = "";
    }
    if (target) {
      window.scrollTo({ top: target.offsetTop - 100, behavior: "smooth" });
      document.querySelectorAll(".nav-link").forEach((l) => l.classList.remove("active"));
      this.classList.add("active");
    }
  });
});

// Navbar + overlay scroll behaviour
window.addEventListener("scroll", () => {
  const navbar = document.querySelector(".navbar");
  const overlay = document.querySelector(".background-overlay");
  const overlayOpacity = 0.7 + 0.15 * Math.min(window.scrollY / window.innerHeight, 1);
  if (overlay) overlay.style.background = `rgba(0, 0, 0, ${overlayOpacity})`;
  if (navbar) {
    if (window.scrollY > 100) {
      navbar.style.background = "rgba(15, 15, 20, 0.75)";
      navbar.style.backdropFilter = "blur(25px) saturate(150%)";
      navbar.style.boxShadow = "0 4px 24px rgba(0, 0, 0, 0.5), inset 0 1px 0 rgba(255, 255, 255, 0.08)";
    } else {
      navbar.style.background = "rgba(10, 10, 15, 0.6)";
      navbar.style.backdropFilter = "blur(20px) saturate(140%)";
      navbar.style.boxShadow = "0 4px 24px rgba(0, 0, 0, 0.4), inset 0 1px 0 rgba(255, 255, 255, 0.05)";
    }
  }
  // Active section tracking
  const sections = document.querySelectorAll("section[id]");
  const navLinks = document.querySelectorAll(".nav-link");
  const checkpointDots = document.querySelectorAll(".checkpoint-dot");
  let activeId = "";
  sections.forEach((s) => {
    if (window.scrollY >= s.offsetTop - 150) activeId = s.getAttribute("id");
  });
  navLinks.forEach((l) => {
    l.classList.remove("active");
    if (l.getAttribute("href") === "#" + activeId) l.classList.add("active");
  });
  checkpointDots.forEach((d) => {
    d.classList.remove("active");
    if (d.getAttribute("data-section") === activeId) d.classList.add("active");
  });
});

// IntersectionObserver scroll reveals (.stat-item, .contact-item)
const observerOptions = { threshold: 0.1, rootMargin: "0px 0px -50px 0px" };
const observer = new IntersectionObserver((entries) => {
  entries.forEach((entry) => {
    if (entry.isIntersecting) {
      entry.target.style.opacity = "1";
      entry.target.style.transform = "translateY(0)";
    }
  });
}, observerOptions);
document.addEventListener("DOMContentLoaded", () => {
  document.querySelectorAll(".stat-item, .contact-item").forEach((el) => {
    el.style.opacity = "0";
    el.style.transform = "translateY(30px)";
    el.style.transition = "opacity 0.6s ease, transform 0.6s ease";
    observer.observe(el);
  });
});

// Loading screen — Radiance Preloader (SVG Ring + Exit)
window.addEventListener("load", () => {
  const loadingScreen = document.getElementById("loadingScreen");
  const ringFill = document.getElementById("loaderRingFill");
  if (!loadingScreen) return;

  const duration = 1600; // ms for 0→100%
  const start = performance.now();
  const dashArray = 553; // Circumference for r=88

  function tick(now) {
    const elapsed = now - start;
    const t = Math.min(elapsed / duration, 1);
    // Ease-out cubic
    const eased = 1 - Math.pow(1 - t, 3);
    
    if (ringFill) {
      // Animate dash offset from 553 down to 0
      ringFill.style.strokeDashoffset = dashArray - (dashArray * eased);
    }

    if (t < 1) {
      requestAnimationFrame(tick);
    } else {
      // Progress complete — hold briefly, then exit choreography
      setTimeout(() => {
        loadingScreen.classList.add("exit");
        setTimeout(() => { loadingScreen.style.display = "none"; }, 1000);
      }, 400);
    }
  }
  
  // Slight delay before starting progress ring to let logo materialize
  setTimeout(() => {
    requestAnimationFrame(tick);
  }, 300);
});
document.body.style.opacity = "1";

// Magnetic button pull
document.addEventListener("DOMContentLoaded", () => {
  const magneticBtns = document.querySelectorAll(".hero-btn-glass, .featured-cta-btn, .filter-btn");
  const RADIUS = 45;
  const STRENGTH = 0.35;
  magneticBtns.forEach((btn) => {
    btn.addEventListener("mousemove", (e) => {
      const rect = btn.getBoundingClientRect();
      const dx = e.clientX - (rect.left + rect.width / 2);
      const dy = e.clientY - (rect.top + rect.height / 2);
      if (Math.hypot(dx, dy) < RADIUS) {
        btn.style.transform = `translate(${dx * STRENGTH}px, ${dy * STRENGTH}px)`;
        btn.style.transition = "transform 0.15s cubic-bezier(0.16,1,0.3,1)";
      }
    });
    btn.addEventListener("mouseleave", () => {
      btn.style.transform = "";
      btn.style.transition = "transform 0.5s cubic-bezier(0.16,1,0.3,1)";
    });
  });
});

// Kinetic scroll skew + cassette tilt
document.addEventListener("DOMContentLoaded", () => {
  let lastScrollTop = window.scrollY || document.documentElement.scrollTop;
  let smoothedVelocity = 0;
  let lastTime = performance.now();

  const updateKineticScroll = (time) => {
    const dt = time - lastTime;
    lastTime = time;
    const currentScrollTop = window.scrollY || document.documentElement.scrollTop;
    const velocity = dt > 0 ? (currentScrollTop - lastScrollTop) / dt : 0;
    lastScrollTop = currentScrollTop;
    const targetSkew = velocity * -4.0;
    smoothedVelocity += (targetSkew - smoothedVelocity) * 0.1;
    let skew = smoothedVelocity;
    if (skew > 8) skew = 8;
    if (skew < -8) skew = -8;
    if (Math.abs(skew) > 0.01 || Math.abs(smoothedVelocity) > 0.01) {
      document.documentElement.style.setProperty("--scroll-skew", `${skew}deg`);
    } else {
      document.documentElement.style.setProperty("--scroll-skew", "0deg");
      smoothedVelocity = 0;
    }
    requestAnimationFrame(updateKineticScroll);
  };
  requestAnimationFrame(updateKineticScroll);

  // Cassette tilt (non-touch only)
  const cassettes = document.querySelectorAll(".event-cassette");
  const isTouchDevice = "ontouchstart" in window || navigator.maxTouchPoints > 0;
  if (!isTouchDevice) {
    cassettes.forEach((card) => {
      let tiltRAF = null;
      card.addEventListener("mousemove", (e) => {
        if (tiltRAF) cancelAnimationFrame(tiltRAF);
        tiltRAF = requestAnimationFrame(() => {
          const rect = card.getBoundingClientRect();
          const normalX = ((e.clientX - rect.left) - rect.width / 2) / (rect.width / 2);
          const normalY = ((e.clientY - rect.top) - rect.height / 2) / (rect.height / 2);
          const tiltX = -normalY * 4;
          const tiltY = normalX * 4;
          card.style.transform = `perspective(1000px) skewY(var(--scroll-skew, 0deg)) rotateX(${tiltX}deg) rotateY(${tiltY}deg) translateX(${normalX * 4}px) translateY(${normalY * 4}px) scale(1.02)`;
          card.style.transition = "transform 0.1s ease-out, box-shadow 0.3s ease";
        });
      });
      card.addEventListener("mouseleave", () => {
        if (tiltRAF) cancelAnimationFrame(tiltRAF);
        card.style.transition = "transform 0.6s cubic-bezier(0.16, 1, 0.3, 1), box-shadow 0.3s ease";
        card.style.transform = "";
      });
    });
  }
});

// Universal Signature Image 3D Tilt & Glare Handler
document.addEventListener("DOMContentLoaded", () => {
  const initMSCImages = () => {
    const boxes = document.querySelectorAll(".msc-image-box");
    boxes.forEach((box) => {
      if (box.dataset.mscTiltInit === "true") return;
      box.dataset.mscTiltInit = "true";

      box.addEventListener("mousemove", (e) => {
        const rect = box.getBoundingClientRect();
        const x = e.clientX - rect.left;
        const y = e.clientY - rect.top;
        const centerX = rect.width / 2;
        const centerY = rect.height / 2;

        const rotateX = ((y - centerY) / centerY) * -6;
        const rotateY = ((x - centerX) / centerX) * 6;

        box.style.setProperty("--mouse-x", `${(x / rect.width) * 100}%`);
        box.style.setProperty("--mouse-y", `${(y / rect.height) * 100}%`);
        box.style.transform = `perspective(1000px) rotateX(${rotateX}deg) rotateY(${rotateY}deg) scale3d(1.02, 1.02, 1.02)`;
      });

      box.addEventListener("mouseleave", () => {
        box.style.transform = "perspective(1000px) rotateX(0deg) rotateY(0deg) scale3d(1, 1, 1)";
      });
    });
  };

  initMSCImages();

  // Re-run whenever DOM updates dynamically
  const observer = new MutationObserver(initMSCImages);
  observer.observe(document.body, { childList: true, subtree: true });
});

